    for k in [1, 2, 3, 4, 5, 6, 7]:
        t.insert(k)
    t.delete(1)
    t.delete(2)
    t.delete(3)
    remaining = [4, 5, 6, 7]
    assert t.to_sorted_list() == remaining
    for k in remaining:
        assert t.search(k)

